+/// Find the position of the first CRLF (`\r\n`) in `buf`.
+///
+/// Returns the index of `\r` when found.
+#[inline]
+fn find_crlf(buf: &[u8]) -> Option<usize> {
+    if buf.len() < 2 {
+        return None;
+    }
+
+    let mut i = 1;
+    while i < buf.len() {
+        if buf[i - 1] == b'\r' && buf[i] == b'\n' {
+            return Some(i - 1);
+        }
+        i += 1;
+    }
+    None
 }

