+    for (name, value) in headers {
+        if name.eq_ignore_ascii_case("transfer-encoding") {
+            if transfer_encoding.is_some() {
+                return Err(HttpError::DuplicateTransferEncoding);
+            }
+            transfer_encoding = Some(value.as_str());
